import java.util.*;
public class AdjList {
    public static void main(String[] a){
        int n=5;int[][] edges={{0,1},{0,2},{1,3},{2,4}};
        List<List<Integer>> adj=new ArrayList<>();
        for(int i=0;i<n;i++)adj.add(new ArrayList<>());
        for(int[] e:edges){adj.get(e[0]).add(e[1]);adj.get(e[1]).add(e[0]);}
        System.out.println(adj.get(0)); // [1,2]
        System.out.println(adj.get(1)); // [0,3]
        System.out.println("O(V+E) space — most efficient for sparse graphs");
    }
}

import java.util.*;
public class BFSGraph {
    static List<Integer> bfs(List<List<Integer>> adj, int src){
        boolean[] vis=new boolean[adj.size()];List<Integer> order=new ArrayList<>();
        Queue<Integer> q=new ArrayDeque<>();q.offer(src);vis[src]=true;
        while(!q.isEmpty()){int n=q.poll();order.add(n);for(int nb:adj.get(n))if(!vis[nb]){vis[nb]=true;q.offer(nb);}}
        return order;
    }
    public static void main(String[] a){int n=6;int[][] edges={{0,1},{0,2},{1,3},{2,4},{3,5}};List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:edges){adj.get(e[0]).add(e[1]);adj.get(e[1]).add(e[0]);}System.out.println(bfs(adj,0));System.out.println("BFS = shortest path in unweighted graph. O(V+E).");}
}

import java.util.*;
public class DFSGraph {
    static List<Integer> order=new ArrayList<>();
    static void dfs(List<List<Integer>> adj, boolean[] vis, int n){vis[n]=true;order.add(n);for(int nb:adj.get(n))if(!vis[nb])dfs(adj,vis,nb);}
    public static void main(String[] a){int n=6;int[][] edges={{0,1},{0,2},{1,3},{2,4},{3,5}};List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:edges){adj.get(e[0]).add(e[1]);adj.get(e[1]).add(e[0]);}order=new ArrayList<>();dfs(adj,new boolean[n],0);System.out.println(order);System.out.println("DFS explores depth-first. Order depends on adjacency list ordering.");}
}

import java.util.*;
public class ConnComp {
    static int[] parent,rank;
    static int find(int x){if(parent[x]!=x)parent[x]=find(parent[x]);return parent[x];}
    static boolean union(int a,int b){int pa=find(a),pb=find(b);if(pa==pb)return false;if(rank[pa]<rank[pb]){int t=pa;pa=pb;pb=t;}parent[pb]=pa;if(rank[pa]==rank[pb])rank[pa]++;return true;}
    static int countComponents(int n, int[][] edges){parent=new int[n];rank=new int[n];for(int i=0;i<n;i++)parent[i]=i;int comp=n;for(int[] e:edges)if(union(e[0],e[1]))comp--;return comp;}
    public static void main(String[] a){System.out.println(countComponents(5,new int[][]{{0,1},{1,2},{3,4}}));System.out.println(countComponents(5,new int[][]{{0,1},{1,2},{2,3},{3,4}}));System.out.println("Union-Find: O(α(n)) per operation. Practically O(1).");}
}

import java.util.*;
public class CycleUndirected {
    static boolean hasCycle(int n, int[][] edges){
        List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:edges){adj.get(e[0]).add(e[1]);adj.get(e[1]).add(e[0]);}
        boolean[] vis=new boolean[n];
        for(int i=0;i<n;i++)if(!vis[i]&&dfs(adj,vis,i,-1))return true;
        return false;}
    static boolean dfs(List<List<Integer>> adj,boolean[] vis,int cur,int par){vis[cur]=true;for(int nb:adj.get(cur)){if(!vis[nb]){if(dfs(adj,vis,nb,cur))return true;}else if(nb!=par)return true;}return false;}
    public static void main(String[] a){System.out.println(hasCycle(4,new int[][]{{0,1},{1,2},{2,0},{2,3}}));System.out.println(hasCycle(4,new int[][]{{0,1},{1,2},{2,3}}));System.out.println("DFS: cycle if visited neighbor != parent. O(V+E).");}
}

import java.util.*;
public class Bipartite {
    static boolean isBipartite(int[][] graph){int n=graph.length;int[] color=new int[n];Arrays.fill(color,-1);for(int i=0;i<n;i++){if(color[i]!=-1)continue;Queue<Integer> q=new ArrayDeque<>();q.offer(i);color[i]=0;while(!q.isEmpty()){int node=q.poll();for(int nb:graph[node]){if(color[nb]==-1){color[nb]=1-color[node];q.offer(nb);}else if(color[nb]==color[node])return false;}}};return true;}
    public static void main(String[] a){System.out.println(isBipartite(new int[][]{{1,2,3},{0,2},{0,1,3},{0,2}}));System.out.println(isBipartite(new int[][]{{1,3},{0,2},{1,3},{0,2}}));System.out.println("2-coloring BFS: if neighbor same color → not bipartite. O(V+E)");}
}

import java.util.*;
public class TopoSort {
    static int[] topoSort(int n, int[][] edges){int[] indegree=new int[n];List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:edges){adj.get(e[0]).add(e[1]);indegree[e[1]]++;}Queue<Integer> q=new ArrayDeque<>();for(int i=0;i<n;i++)if(indegree[i]==0)q.offer(i);int[] order=new int[n];int idx=0;while(!q.isEmpty()){int node=q.poll();order[idx++]=node;for(int nb:adj.get(node))if(--indegree[nb]==0)q.offer(nb);}return idx==n?order:new int[]{};}
    public static void main(String[] a){System.out.println(Arrays.toString(topoSort(6,new int[][]{{5,2},{5,0},{4,0},{4,1},{2,3},{3,1}})));System.out.println("Kahn's: BFS from 0-indegree nodes. Cycle → fewer than n processed. O(V+E).");}
}

import java.util.*;
public class CourseSchedule {
    static boolean canFinish(int n, int[][] prereqs){int[] indeg=new int[n];List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] p:prereqs){adj.get(p[1]).add(p[0]);indeg[p[0]]++;}Queue<Integer> q=new ArrayDeque<>();for(int i=0;i<n;i++)if(indeg[i]==0)q.offer(i);int done=0;while(!q.isEmpty()){int c=q.poll();done++;for(int nb:adj.get(c))if(--indeg[nb]==0)q.offer(nb);}return done==n;}
    public static void main(String[] a){System.out.println(canFinish(2,new int[][]{{1,0}}));System.out.println(canFinish(2,new int[][]{{1,0},{0,1}}));System.out.println("Topo sort: if all courses processed → no cycle → can finish. O(V+E).");}
}

import java.util.*;
public class Dijkstra {
    static int[] shortestPath(int n, int[][] edges, int src){int[] dist=new int[n];Arrays.fill(dist,Integer.MAX_VALUE);dist[src]=0;List<List<int[]>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:edges){adj.get(e[0]).add(new int[]{e[1],e[2]});adj.get(e[1]).add(new int[]{e[0],e[2]});}PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[1]-b[1]);pq.offer(new int[]{src,0});while(!pq.isEmpty()){int[] top=pq.poll();int u=top[0],d=top[1];if(d>dist[u])continue;for(int[] nb:adj.get(u)){if(dist[u]+nb[1]<dist[nb[0]]){dist[nb[0]]=dist[u]+nb[1];pq.offer(new int[]{nb[0],dist[nb[0]]});}}}return dist;}
    public static void main(String[] a){int[][] edges={{0,1,4},{0,2,1},{2,1,2},{1,3,1}};System.out.println(Arrays.toString(shortestPath(4,edges,0)));System.out.println("[0, 3, 1, 4] — Dijkstra O((V+E) log V). No negative edges.");}
}

public class UnionFind {
    int[] parent,rank;
    UnionFind(int n){parent=new int[n];rank=new int[n];for(int i=0;i<n;i++)parent[i]=i;}
    int find(int x){if(parent[x]!=x)parent[x]=find(parent[x]);return parent[x];}
    boolean union(int a,int b){int pa=find(a),pb=find(b);if(pa==pb)return false;if(rank[pa]<rank[pb]){int t=pa;pa=pb;pb=t;}parent[pb]=pa;if(rank[pa]==rank[pb])rank[pa]++;return true;}
    public static void main(String[] a){UnionFind uf=new UnionFind(5);uf.union(0,1);uf.union(2,3);System.out.println(uf.find(0)==uf.find(1));System.out.println(uf.find(0)==uf.find(2));uf.union(1,2);System.out.println(uf.find(0)==uf.find(3));System.out.println("Path compression+rank: O(α(n)) ≈ O(1) amortized. Critical for Kruskal/cycles.");}
}

import java.util.*;
public class GraphSynth {
    static boolean canFinish(int n,int[][] p){int[] ind=new int[n];List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:p){adj.get(e[1]).add(e[0]);ind[e[0]]++;}Queue<Integer> q=new ArrayDeque<>();for(int i=0;i<n;i++)if(ind[i]==0)q.offer(i);int done=0;while(!q.isEmpty()){int c=q.poll();done++;for(int nb:adj.get(c))if(--ind[nb]==0)q.offer(nb);}return done==n;}
    static int[] dijkstra(int n,int[][] edges,int src){int[] d=new int[n];Arrays.fill(d,Integer.MAX_VALUE);d[src]=0;List<List<int[]>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:edges){adj.get(e[0]).add(new int[]{e[1],e[2]});adj.get(e[1]).add(new int[]{e[0],e[2]});}PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[1]-b[1]);pq.offer(new int[]{src,0});while(!pq.isEmpty()){int[] top=pq.poll();int u=top[0],dd=top[1];if(dd>d[u])continue;for(int[] nb:adj.get(u))if(d[u]+nb[1]<d[nb[0]]){d[nb[0]]=d[u]+nb[1];pq.offer(new int[]{nb[0],d[nb[0]]});}}return d;}
    public static void main(String[] a){System.out.println(canFinish(2,new int[][]{{1,0}}));System.out.println(canFinish(2,new int[][]{{1,0},{0,1}}));System.out.println(Arrays.toString(dijkstra(4,new int[][]{{0,1,4},{0,2,1},{2,1,2},{1,3,1}},0)));boolean ok=canFinish(2,new int[][]{{1,0}})&&!canFinish(2,new int[][]{{1,0},{0,1}});System.out.println("All pass: "+ok);}
}

import java.util.*;
public class M37Final {
    static int numIslands(char[][] g){int r=g.length,c=g[0].length,cnt=0;int[][] d={{0,1},{0,-1},{1,0},{-1,0}};for(int i=0;i<r;i++)for(int j=0;j<c;j++){if(g[i][j]=='1'){cnt++;Queue<int[]> q=new ArrayDeque<>();q.offer(new int[]{i,j});g[i][j]='0';while(!q.isEmpty()){int[] p=q.poll();for(int[] dd:d){int ni=p[0]+dd[0],nj=p[1]+dd[1];if(ni>=0&&ni<r&&nj>=0&&nj<c&&g[ni][nj]=='1'){g[ni][nj]='0';q.offer(new int[]{ni,nj});}}}}}return cnt;}
    static boolean canFinish(int n,int[][] p){int[] ind=new int[n];List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:p){adj.get(e[1]).add(e[0]);ind[e[0]]++;}Queue<Integer> q=new ArrayDeque<>();for(int i=0;i<n;i++)if(ind[i]==0)q.offer(i);int done=0;while(!q.isEmpty()){done++;int c=q.poll();for(int nb:adj.get(c))if(--ind[nb]==0)q.offer(nb);}return done==n;}
    static int[] parent=new int[0];
    static int find(int x){if(parent[x]!=x)parent[x]=find(parent[x]);return parent[x];}
    static boolean union(int a,int b){int pa=find(a),pb=find(b);if(pa==pb)return false;parent[pb]=pa;return true;}
    static int numComp(int n,int[][] e){parent=new int[n];for(int i=0;i<n;i++)parent[i]=i;int comp=n;for(int[] ed:e)if(union(ed[0],ed[1]))comp--;return comp;}
    public static void main(String[] a){System.out.println("islands="+numIslands(new char[][]{{'1','1','0'},{'0','1','0'},{'0','0','1'}}));System.out.println("courseOk="+canFinish(2,new int[][]{{1,0}}));System.out.println("components="+numComp(5,new int[][]{{0,1},{1,2},{3,4}}));boolean ok=canFinish(2,new int[][]{{1,0}})&&numComp(5,new int[][]{{0,1},{1,2},{3,4}})==2;System.out.println("All pass: "+ok);}
}
